{
  "name": "@mindful-engineer/site",
  "private": true,
  "version": "0.1.0",
  "type": "module",
  "scripts": {
    "dev": "astro dev",
    "build": "astro check && astro build",
    "preview": "astro preview"
  },
  "dependencies": {
    "astro": "^4.16.18",
    "@astrojs/check": "^0.9.4",
    "@astrojs/mdx": "^3.1.8",
    "sharp": "^0.33.5",
    "typescript": "^5.6.3",
    "zod": "^3.23.8"
  }
}

import { defineConfig } from 'astro/config';
import mdx from '@astrojs/mdx';

export default defineConfig({
  output: 'static',
  site: 'https://mindful.engineer',
  integrations: [mdx()],
  vite: {
    server: {
      fs: {
        allow: ['..'],
      },
    },
  },
});

---
import { site } from '@/content/site';

interface Props {
  title?: string;
  description?: string;
  pathname?: string;
}

const { title = site.title, description = site.description, pathname = '/' } = Astro.props;
const pageTitle = title === site.title ? title : `${title} · ${site.title}`;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>{pageTitle}</title>
    <meta name="description" content={description} />
    <link rel="canonical" href={`https://mindful.engineer${pathname}`} />
  </head>
  <body>
    <div class="site-shell">
      <header class="site-header">
        <div class="container site-header__inner">
          <a href="/" class="site-brand">
            <span class="site-brand__mark"></span>
            <span>Mindful Engineer</span>
          </a>
          <nav class="site-nav" aria-label="Primary">
            {site.navigation.map((item) => (
              <a href={item.href} class:list={[pathname === item.href || (item.href !== '/' && pathname.startsWith(item.href)) ? 'is-active' : undefined]}>{item.label}</a>
            ))}
          </nav>
        </div>
      </header>

      <main class="container site-main">
        <slot />
      </main>

      <footer class="site-footer">
        <div class="container site-footer__grid">
          <section>
            <div class="footer-label">mindful.engineer</div>
            <p>
              A monastery-first reading site for articles, notes, links, and code
              fragments about software, change, and the people in the middle.
            </p>
          </section>
          <section>
            <div class="footer-label">Sections</div>
            <ul>
              {site.footerLinks.sections.map((item) => (
                <li><a href={item.href}>{item.label}</a></li>
              ))}
            </ul>
          </section>
          <section>
            <div class="footer-label">Elsewhere</div>
            <ul>
              {site.footerLinks.elsewhere.map((item) => (
                <li><a href={item.href}>{item.label}</a></li>
              ))}
            </ul>
          </section>
        </div>
        <div class="container site-footer__meta">
          <span>© 2026 Benjamin Kitt · built by hand</span>
          <span>Cloudflare Pages target · Astro static output</span>
        </div>
      </footer>
    </div>
  </body>
</html>

<style is:global>
  :root {
    --font-serif: "EB Garamond", "Sorts Mill Goudy", Georgia, serif;
    --font-mono: "JetBrains Mono", "SFMono-Regular", Menlo, monospace;
    --bg: oklch(96.5% 0.018 70);
    --bg-soft: oklch(94% 0.024 70);
    --ink: oklch(20% 0.02 40);
    --ink-soft: oklch(40% 0.02 40);
    --ink-muted: oklch(60% 0.016 40);
    --rule: oklch(82% 0.016 60);
    --rule-soft: oklch(90% 0.014 60);
    --accent: oklch(44% 0.14 30);
    --accent-soft: oklch(88% 0.05 30);
    --container: 72rem;
    --measure: 64ch;
  }

  * { box-sizing: border-box; }
  html, body { margin: 0; padding: 0; }
  body {
    background: var(--bg);
    color: var(--ink);
    font-family: var(--font-serif);
    font-size: 1.125rem;
    line-height: 1.65;
  }
  a {
    color: inherit;
    text-decoration: underline;
    text-decoration-color: var(--rule);
    text-underline-offset: 0.2em;
  }
  a:hover { color: var(--accent); text-decoration-color: var(--accent); }
  h1, h2, h3, h4, h5, h6 { font-weight: 500; line-height: 1.1; margin: 0; }
  p { margin: 0 0 1rem; }
  ul, ol { margin: 0 0 1rem; }
  code, pre { font-family: var(--font-mono); }
  pre {
    background: color-mix(in oklab, var(--bg-soft) 78%, white 22%);
    border: 1px solid var(--rule);
    overflow-x: auto;
    padding: 1rem;
    font-size: 0.9rem;
    line-height: 1.6;
  }
  .container {
    width: min(calc(100% - 2rem), var(--container));
    margin: 0 auto;
  }
  .site-shell { min-height: 100vh; display: flex; flex-direction: column; }
  .site-header {
    position: sticky;
    top: 0;
    z-index: 10;
    backdrop-filter: blur(10px);
    background: color-mix(in oklab, var(--bg) 92%, transparent);
    border-bottom: 1px solid var(--rule-soft);
  }
  .site-header__inner {
    display: flex;
    gap: 1.5rem;
    align-items: baseline;
    justify-content: space-between;
    padding: 1.25rem 0;
  }
  .site-brand {
    display: inline-flex;
    gap: 0.75rem;
    align-items: baseline;
    text-decoration: none;
    font-size: 1.375rem;
  }
  .site-brand__mark {
    width: 0.55rem;
    height: 0.55rem;
    border: 1.5px solid currentColor;
    border-radius: 999px;
    transform: translateY(-0.05rem);
  }
  .site-nav {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    font-family: var(--font-mono);
    font-size: 0.8rem;
    letter-spacing: 0.06em;
    text-transform: uppercase;
  }
  .site-nav a { text-decoration: none; color: var(--ink-soft); border-bottom: 1px solid transparent; }
  .site-nav a.is-active,
  .site-nav a:hover { color: var(--ink); border-bottom-color: var(--accent); }
  .site-main { flex: 1; padding: 3rem 0 5rem; }
  .site-footer {
    border-top: 1px solid var(--rule-soft);
    padding: 3rem 0;
    margin-top: auto;
  }
  .site-footer__grid {
    display: grid;
    grid-template-columns: 1.4fr 1fr 1fr;
    gap: 2rem;
  }
  .footer-label,
  .hero__kicker,
  .section-header,
  .archive-year,
  .entry-meta,
  .detail-meta,
  .page-facts dt,
  .now-block__label {
    font-family: var(--font-mono);
    font-size: 0.72rem;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    color: var(--ink-muted);
  }
  .site-footer ul { list-style: none; padding: 0; }
  .site-footer__meta {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid var(--rule-soft);
    font-family: var(--font-mono);
    font-size: 0.72rem;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--ink-muted);
  }
  .hero {
    border-bottom: 1px solid var(--rule-soft);
    padding: 1rem 0 3rem;
    margin-bottom: 3rem;
    position: relative;
  }
  .hero::after {
    content: '';
    position: absolute;
    right: -2rem;
    top: -2rem;
    width: min(34vw, 18rem);
    aspect-ratio: 1;
    border-radius: 999px;
    border: 1px solid color-mix(in oklab, var(--accent) 40%, transparent);
    opacity: 0.3;
    pointer-events: none;
  }
  .hero h1 {
    font-size: clamp(2.5rem, 6vw, 4.5rem);
    max-width: 12ch;
    letter-spacing: -0.03em;
    margin-bottom: 1rem;
  }
  .hero__summary { max-width: 52ch; color: var(--ink-soft); font-size: 1.25rem; font-style: italic; }
  .hero__meta {
    display: flex;
    flex-wrap: wrap;
    gap: 1.5rem;
    margin-top: 1.75rem;
  }
  .hero__meta div, .detail-meta { display: grid; gap: 0.25rem; }
  .hero__meta dt { margin: 0; }
  .hero__meta dd { margin: 0; font-family: var(--font-mono); font-size: 0.95rem; color: var(--ink); }
  .section-header {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    align-items: baseline;
    border-bottom: 1px solid var(--rule);
    padding-bottom: 0.75rem;
    margin-bottom: 1.5rem;
  }
  .section-header h2 { font-size: 0.8rem; }
  .entry-grid {
    display: grid;
    grid-template-columns: repeat(12, minmax(0, 1fr));
    gap: 1rem;
  }
  .entry-card {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    border: 1px solid var(--rule);
    padding: 1.5rem;
    text-decoration: none;
    background: color-mix(in oklab, var(--bg) 90%, white 10%);
  }
  .entry-card:hover { border-color: var(--ink); background: var(--bg-soft); }
  .entry-card--featured { grid-column: span 6; }
  .entry-card--article { grid-column: span 8; }
  .entry-card--note { grid-column: span 4; background: var(--bg-soft); }
  .entry-card--link,
  .entry-card--snippet { grid-column: span 6; }
  .entry-card h3 { font-size: clamp(1.4rem, 3vw, 2rem); letter-spacing: -0.02em; }
  .entry-card__meta,
  .entry-card__source,
  .entry-card__tags {
    font-family: var(--font-mono);
    font-size: 0.72rem;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--ink-muted);
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    flex-wrap: wrap;
  }
  .entry-card__note { font-size: 1.2rem; font-style: italic; }
  .entry-card p { color: var(--ink-soft); }
  .archive-table { border-top: 1px solid var(--rule); }
  .archive-year { padding: 1rem 0 0.75rem; border-bottom: 1px solid var(--rule-soft); }
  .archive-row {
    display: grid;
    grid-template-columns: 6rem 6rem 1fr 5rem;
    gap: 1rem;
    align-items: baseline;
    border-bottom: 1px solid var(--rule-soft);
    padding: 0.9rem 0;
    text-decoration: none;
  }
  .archive-row:hover { background: var(--bg-soft); }
  .detail-header,
  .detail-body,
  .static-page,
  .now-grid {
    max-width: var(--measure);
  }
  .detail-header { margin-bottom: 3rem; }
  .detail-header h1 { font-size: clamp(2.3rem, 5vw, 3.8rem); margin-bottom: 0.75rem; letter-spacing: -0.03em; }
  .detail-subtitle { font-size: 1.25rem; font-style: italic; color: var(--ink-soft); margin-bottom: 1.5rem; }
  .detail-meta {
    display: flex;
    gap: 1.25rem;
    flex-wrap: wrap;
    padding-top: 1rem;
    border-top: 1px solid var(--rule-soft);
    margin-bottom: 2rem;
  }
  .detail-body h2 { font-size: 1.8rem; margin: 3rem 0 1rem; }
  .detail-body blockquote {
    border-left: 2px solid var(--accent);
    margin: 2rem 0;
    padding: 0.5rem 0 0.5rem 1.25rem;
    font-size: 1.5rem;
    font-style: italic;
  }
  .detail-footer {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
    margin-top: 3rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--rule);
    font-family: var(--font-mono);
    font-size: 0.8rem;
  }
  .detail-footer a { text-decoration: none; }
  .list-stack { display: grid; gap: 1rem; }
  .list-row {
    display: grid;
    grid-template-columns: 10rem 1fr;
    gap: 1rem;
    padding: 1.25rem;
    border: 1px solid var(--rule);
    text-decoration: none;
  }
  .list-row:hover { background: var(--bg-soft); }
  .list-row__date { font-family: var(--font-mono); font-size: 0.8rem; color: var(--ink-muted); }
  .list-row__body h2 { font-size: 1.35rem; margin-bottom: 0.35rem; }
  .list-row__body p { color: var(--ink-soft); }
  .static-page > p:first-of-type { font-size: 1.4rem; line-height: 1.45; color: var(--ink); }
  .page-facts {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 1rem 2rem;
    margin-top: 2rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--rule-soft);
  }
  .page-facts dd { margin: 0.3rem 0 0; }
  .now-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 1rem;
  }
  .now-block {
    border: 1px solid var(--rule);
    padding: 1.25rem;
    background: color-mix(in oklab, var(--bg) 92%, white 8%);
  }
  .now-block--wide { grid-column: 1 / -1; }
  .now-block ul { padding-left: 1rem; margin: 0; }
  @media (max-width: 900px) {
    .site-header__inner,
    .site-footer__meta,
    .section-header,
    .detail-footer {
      flex-direction: column;
      display: flex;
      align-items: flex-start;
    }
    .site-footer__grid,
    .page-facts,
    .now-grid { grid-template-columns: 1fr; }
    .entry-card,
    .entry-card--featured,
    .entry-card--article,
    .entry-card--note,
    .entry-card--link,
    .entry-card--snippet { grid-column: 1 / -1; }
    .archive-row,
    .list-row { grid-template-columns: 1fr; }
    .site-nav { gap: 0.75rem; }
  }
</style>

import { entries, type ArticleEntry, type Entry, type EntryType, staticPages } from '@/content/entries';

const typeOrder: EntryType[] = ['article', 'note', 'link', 'snippet'];

export function sortByPublishedDesc<T extends Entry>(items: T[]) {
  return [...items].sort(
    (a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime(),
  );
}

export function getEntriesByType<T extends EntryType>(type: T) {
  return sortByPublishedDesc(entries.filter((entry) => entry.type === type)) as Extract<Entry, { type: T }>[];
}

export function getFeaturedArticles() {
  return getEntriesByType('article').filter((entry) => entry.featured);
}

export function getRecentStream() {
  return sortByPublishedDesc(entries);
}

export function getArchiveGroups() {
  const groups = new Map<number, Entry[]>();
  for (const entry of sortByPublishedDesc(entries)) {
    const year = new Date(entry.publishedAt).getUTCFullYear();
    const bucket = groups.get(year) ?? [];
    bucket.push(entry);
    groups.set(year, bucket);
  }
  return [...groups.entries()].map(([year, items]) => ({ year, items }));
}

export function getEntryUrl(entry: Entry) {
  switch (entry.type) {
    case 'article':
      return `/articles/${entry.slug}`;
    case 'note':
      return `/notes/${entry.slug}`;
    case 'link':
      return `/links/${entry.slug}`;
    case 'snippet':
      return `/snippets/${entry.slug}`;
  }
}

export function getEntryLabel(type: EntryType) {
  return {
    article: 'Article',
    note: 'Note',
    link: 'Link',
    snippet: 'Snippet',
  }[type];
}

export function getArticleNeighbors(article: ArticleEntry) {
  const articles = getEntriesByType('article');
  const index = articles.findIndex((item) => item.id === article.id);
  return {
    newer: index > 0 ? articles[index - 1] : undefined,
    older: index >= 0 && index < articles.length - 1 ? articles[index + 1] : undefined,
  };
}

export function getStaticPage<T extends keyof typeof staticPages>(slug: T): (typeof staticPages)[T] {
  return staticPages[slug];
}

export function getContentCounts() {
  return typeOrder.map((type) => ({ type, count: entries.filter((entry) => entry.type === type).length }));
}

export function formatDate(value: string, includeTime = false) {
  const date = new Date(value);
  const day = date.getUTCDate();
  const month = date.toLocaleString('en-US', { month: 'short', timeZone: 'UTC' });
  const year = date.getUTCFullYear();

  if (!includeTime) {
    return `${day} ${month} ${year}`;
  }

  const time = date.toLocaleTimeString('en-US', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: 'UTC',
  });

  return `${day} ${month} ${year} · ${time} UTC`;
}

export function formatDateShort(value: string) {
  const date = new Date(value);
  const day = String(date.getUTCDate()).padStart(2, '0');
  const month = date.toLocaleString('en-US', { month: 'short', timeZone: 'UTC' }).toLowerCase();
  return `${day} ${month}`;
}

---
import EntryCard from '@/components/EntryCard.astro';
import PageHeader from '@/components/PageHeader.astro';
import SectionHeader from '@/components/SectionHeader.astro';
import { getContentCounts, getFeaturedArticles, getRecentStream } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

const featured = getFeaturedArticles();
const stream = getRecentStream().filter((entry) => !('featured' in entry && entry.featured));
const meta = getContentCounts().map((item) => ({ label: item.type, value: item.count }));
---

<PublicLayout pathname="/">
  <PageHeader
    kicker="mindful.engineer · a working notebook"
    title="Moving fast. Being present."
    summary="A monastery-first reading surface for articles, notes, links, and fragments on software, change, and the people along for the ride."
    meta={meta}
  />

  <SectionHeader title="Featured writing" detail={`${featured.length} articles`} />
  <div class="entry-grid">
    {featured.map((entry) => (
      <EntryCard entry={entry} featured />
    ))}
  </div>

  <SectionHeader title="Recent stream" detail="Across all published types" />
  <div class="entry-grid">
    {stream.map((entry) => (
      <EntryCard entry={entry} />
    ))}
  </div>
</PublicLayout>

---
import EntryCard from '@/components/EntryCard.astro';
import PageHeader from '@/components/PageHeader.astro';
import { getEntriesByType } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

const articles = getEntriesByType('article');
---

<PublicLayout title="Articles" pathname="/articles">
  <PageHeader
    kicker="collected · articles"
    title="Articles"
    summary="Longer pieces. Published when they are ready, not to a schedule."
    meta={[{ label: 'published', value: articles.length }]}
  />

  <div class="entry-grid">
    {articles.map((entry) => (
      <EntryCard entry={entry} featured={entry.featured ?? false} />
    ))}
  </div>
</PublicLayout>

---
import type { ArticleEntry } from '@/content/entries';
import { entries } from '@/content/entries';
import { formatDate, getArticleNeighbors } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

export function getStaticPaths() {
  return entries
    .filter((entry): entry is ArticleEntry => entry.type === 'article')
    .map((entry) => ({ params: { slug: entry.slug }, props: { entry } }));
}

const { entry } = Astro.props;
const neighbors = getArticleNeighbors(entry);
---

<PublicLayout title={entry.title} description={entry.summary} pathname={`/articles/${entry.slug}`}>
  <article class="detail-header">
    <div class="hero__kicker">Article · {formatDate(entry.publishedAt)} · {entry.readMinutes} minute read</div>
    <h1>{entry.title}</h1>
    <p class="detail-subtitle">{entry.subtitle}</p>
    <div class="detail-meta">
      <span>Benjamin Kitt</span>
      {entry.tags && <span>Filed under: {entry.tags.join(', ')}</span>}
    </div>
  </article>

  <div class="detail-body">
    {entry.body.map((block) => {
      if (block.kind === 'paragraph') return <p>{block.text}</p>;
      if (block.kind === 'heading') return <h2>{block.text}</h2>;
      if (block.kind === 'pullquote') return <blockquote>“{block.text}”</blockquote>;
      if (block.kind === 'ordered-list') {
        return (
          <ol>
            {block.items.map((item) => (
              <li>{item}</li>
            ))}
          </ol>
        );
      }
    })}
  </div>

  <nav class="detail-footer" aria-label="Article neighbors">
    <div>
      {neighbors.older && (
        <a href={`/articles/${neighbors.older.slug}`}>
          ← Older · {neighbors.older.title}
        </a>
      )}
    </div>
    <div>
      {neighbors.newer && (
        <a href={`/articles/${neighbors.newer.slug}`}>
          Newer → {neighbors.newer.title}
        </a>
      )}
    </div>
  </nav>
</PublicLayout>

---
import type { NoteEntry } from '@/content/entries';
import { entries } from '@/content/entries';
import { formatDate } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

export function getStaticPaths() {
  return entries
    .filter((entry): entry is NoteEntry => entry.type === 'note')
    .map((entry) => ({ params: { slug: entry.slug }, props: { entry } }));
}

const { entry } = Astro.props;
---

<PublicLayout title={entry.title ?? 'Note'} description={entry.body} pathname={`/notes/${entry.slug}`}>
  <article class="detail-header">
    <div class="hero__kicker">Note · {formatDate(entry.publishedAt, true)}</div>
    <h1>{entry.title ?? 'Note'}</h1>
  </article>

  <div class="detail-body">
    <p style="font-size:1.5rem;font-style:italic;">{entry.body}</p>
  </div>
</PublicLayout>

---
import type { LinkEntry } from '@/content/entries';
import { entries } from '@/content/entries';
import { formatDate } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

export function getStaticPaths() {
  return entries
    .filter((entry): entry is LinkEntry => entry.type === 'link')
    .map((entry) => ({ params: { slug: entry.slug }, props: { entry } }));
}

const { entry } = Astro.props;
---

<PublicLayout title={entry.title} description={entry.commentary} pathname={`/links/${entry.slug}`}>
  <article class="detail-header">
    <div class="hero__kicker">Link · {formatDate(entry.publishedAt)}</div>
    <h1>{entry.title}</h1>
    <p class="detail-subtitle">Source · <a href={entry.url}>{entry.source} ↗</a></p>
  </article>

  <div class="detail-body">
    <p>{entry.commentary}</p>
  </div>
</PublicLayout>

---
import type { SnippetEntry } from '@/content/entries';
import { entries } from '@/content/entries';
import { formatDate } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

export function getStaticPaths() {
  return entries
    .filter((entry): entry is SnippetEntry => entry.type === 'snippet')
    .map((entry) => ({ params: { slug: entry.slug }, props: { entry } }));
}

const { entry } = Astro.props;
---

<PublicLayout title={entry.title} description={entry.summary} pathname={`/snippets/${entry.slug}`}>
  <article class="detail-header">
    <div class="hero__kicker">Snippet · {formatDate(entry.publishedAt)} · {entry.language}</div>
    <h1>{entry.title}</h1>
    <p class="detail-subtitle">Compact, code-forward notes worth keeping canonically.</p>
  </article>

  <div class="detail-body">
    <pre>{entry.code}</pre>
    <p>{entry.summary}</p>
  </div>
</PublicLayout>

