import PageHeader from '@/components/PageHeader.astro';
import { getStaticPage } from '@/lib/content';
import PublicLayout from '@/layouts/PublicLayout.astro';

const now = getStaticPage('now');
---

<PublicLayout title="Now" pathname="/now">
  <PageHeader
    kicker="static · now"
    title={now.title}
    summary={now.summary}
    meta={[{ label: 'updated', value: now.updatedAt }]}
  />

  <section class="now-grid">
    {now.blocks.map((block: (typeof now.blocks)[number], index: number) => (
      <article class:list={['now-block', index === 0 ? 'now-block--wide' : undefined]}>
        <div class="now-block__label">{block.title}</div>
        {'body' in block && <p>{block.body}</p>}
        {'list' in block && (
          <ul>
            {block.list.map((item: string) => (
              <li>{item}</li>
            ))}
          </ul>
        )}
      </article>
    ))}
  </section>
</PublicLayout>

export type EntryType = 'article' | 'note' | 'link' | 'snippet';

export type BaseEntry = {
  id: string;
  type: EntryType;
  slug: string;
  publishedAt: string;
  updatedAt?: string;
  tags?: string[];
};

export type ArticleEntry = BaseEntry & {
  type: 'article';
  title: string;
  subtitle: string;
  summary: string;
  readMinutes: number;
  featured?: boolean;
  body: Array<
    | { kind: 'paragraph'; text: string }
    | { kind: 'heading'; text: string }
    | { kind: 'pullquote'; text: string }
    | { kind: 'ordered-list'; items: string[] }
  >;
};

export type NoteEntry = BaseEntry & {
  type: 'note';
  body: string;
  title?: string;
};

export type LinkEntry = BaseEntry & {
  type: 'link';
  title: string;
  url: string;
  source: string;
  commentary: string;
};

export type SnippetEntry = BaseEntry & {
  type: 'snippet';
  title: string;
  language: string;
  code: string;
  summary: string;
};

export type Entry = ArticleEntry | NoteEntry | LinkEntry | SnippetEntry;

